from typing import List
from collections import defaultdict

class Solution:
    def maximumSubarraySum(self, nums: List[int], k: int) -> int:
        value_indices = defaultdict(list)
        n = len(nums)
        max_sum = float('-inf')

        # Store indices of each value
        for i, num in enumerate(nums):
            value_indices[num].append(i)

        # Prefix sum array
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]

        # Check all valid subarrays
        for i in range(n):
            target1 = nums[i] + k
            target2 = nums[i] - k

            # Check for subarrays where nums[i] - nums[j] == k
            for j in value_indices.get(target1, []):
                if j > i:
                    subarray_sum = prefix[j + 1] - prefix[i]
                    max_sum = max(max_sum, subarray_sum)

            # Check for subarrays where nums[j] - nums[i] == k
            for j in value_indices.get(target2, []):
                if j > i:
                    subarray_sum = prefix[j + 1] - prefix[i]
                    max_sum = max(max_sum, subarray_sum)

        return max_sum if max_sum != float('-inf') else 0
